import{_ as e,o as c,c as s,a2 as a}from"./chunks/framework.N6Nd-M9-.js";const g=JSON.parse('{"title":"👨‍🏫 五步教导","description":"","frontmatter":{},"headers":[],"relativePath":"notes/企业文化/组长手册/05-五步教导.md","filePath":"notes/企业文化/组长手册/05-五步教导.md"}'),i={name:"notes/企业文化/组长手册/05-五步教导.md"};function l(o,t,r,d,n,p){return c(),s("div",null,[...t[0]||(t[0]=[a('<h1 id="👨‍🏫-五步教导" tabindex="-1">👨‍🏫 五步教导 <a class="header-anchor" href="#👨‍🏫-五步教导" aria-label="Permalink to &quot;👨‍🏫 五步教导&quot;">​</a></h1><blockquote><p>对于组长来说，教育新同事做五步是非常重要的一个课程，因为它关系到的是你能不能建立一支强大的队伍，直接影响到你的发展。</p></blockquote><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">💡 核心要点</p><p class="tc-body">请仔细阅读以下内容，掌握核心知识。</p></div><hr><h2 id="🪜-一、五步教育的重点——理解而非背诵" tabindex="-1">🪜 一、五步教育的重点——理解而非背诵 <a class="header-anchor" href="#🪜-一、五步教育的重点——理解而非背诵" aria-label="Permalink to &quot;🪜 一、五步教育的重点——理解而非背诵&quot;">​</a></h2><div class="tc-container tc-container-blue"><div style="display:flex;flex-direction:column;gap:12px;"><div class="tc-item tc-item-blue tc-body"><strong>了解架构</strong>：要先让他了解五步的架构——五步为什么是这个顺序；每一步的具体做法。 </div><div class="tc-item tc-item-blue tc-body"><strong>互动练习</strong>：可边讲解边与他练习，记住：所谓练习不是填鸭式地你说他听，而是互动式地你说一句，然后请他跟着练习一句。 </div></div><blockquote class="tc-quote tc-quote-blue tc-body" style="margin-top:20px;"><strong>📌 参考说词：</strong><br><br> 为什么第一步是打招呼呢？因为这是人际关系开始的第一步，可拉近彼此的距离、让客户知道我们要和他说话。打完招呼后对方会产生两个问题：你是谁？来做什么？所以第二步介绍自己就是解决这两个问题：告诉客户我们是谁，来做什么。在说明了来意之后，当然就要把产品拿给他看（把产品放在客人的手上），然后向他介绍产品。介绍产品时，因为我们的产品客户都能够一目了然，所以不需要花太多时间，只需要把产品的特色、优点、功能等告诉客户，并推广价格。重点要让客户了解一般市面上售价大约是多少，而我们今天只要多少，完成了这些动作之后，接下来就要试探客户的购买意愿，也就是做成交。做成交的目的不是要强迫客户买，而是清楚我们需不需要再继续花时间在这个客户的身上。我们用积极的思维面对每一个客户，所以我们假设成交给他一些正面的成交问题，然后看看客户的反应是什么，再继续下一个动作，写订单成交或是谢谢再见！ </blockquote></div><hr><h2 id="🪜-二、五步教育需要注意的细节" tabindex="-1">🪜 二、五步教育需要注意的细节 <a class="header-anchor" href="#🪜-二、五步教育需要注意的细节" aria-label="Permalink to &quot;🪜 二、五步教育需要注意的细节&quot;">​</a></h2><div class="tc-grid tc-grid-auto" style="margin-top:20px;"><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">🎯 简单</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 尽量用新同事的方法来教他基础五步，注重五步每个环节的重点细节、精髓要点，确保让他学会。 </p></div><div class="tc-card tc-card-green"><p class="tc-title tc-green">⏳ 耐心</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 每个步骤慢慢教，多点耐心和时间，确定他学会了再进行下一个步骤。 </p></div><div class="tc-card tc-card-orange"><p class="tc-title tc-orange">🔄 重复练习</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 每教完一步，随即让他跟着你练习（先你做他看，再换他做你看）；先认可他做好的部分，再给予建议改变的地方（委婉的语气），然后再练习；认可改变的部分再给另一个建议，再练习……别忘记 <strong>Practice makes perfect! 完美之道在于练习！</strong></p></div></div><div class="tc-grid tc-grid-auto" style="margin-top:15px;"><div class="tc-card tc-card-blue"><p class="tc-subtitle tc-blue">👤 介绍自己</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 自信的眼神，自然的语气…… </p></div><div class="tc-card tc-card-green"><p class="tc-subtitle tc-green">📦 介绍产品</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 产品放在客户的手上 → 递产品的位置、要求客户拿、简单扼要推广产品的特色、功能、比价差。 </p></div><div class="tc-card tc-card-orange"><p class="tc-subtitle tc-orange">✅ 成交</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 成交用语，最少要能说三个（注意说话的声调及肢体动作）。 </p></div><div class="tc-card tc-card-red"><p class="tc-subtitle tc-red">📊 平均法的概念</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 在外出作业之前，必须让他知道平均法的概念（300个顾客里面有285~290人说NO。有10~15人说Yes。遇见的人越多，成交量越大。）同时为今天可能遇到的负面做准备，但也别说得太过夸张，以免新同事还没有出门就被你吓到了！ </p></div><blockquote class="tc-quote tc-quote-green tc-body" style="margin-top:15px;"><strong>📌 参考说词：</strong><br><br> 你昨天看我做了一天，你知道客户拒绝是很正常的，我们做的是平均法的生意，我希望你记得今天的重点不是你要卖多少产品，而是你应该多找一些人练习五步，先把五步熟练并把工作习惯磨练好，这个比你今天做多少业绩更重要，因为我们不是要栽培你成为一个只会销售做业绩的业务员。 </blockquote><hr><h2 id="🪜-三、五步教育的范例" tabindex="-1">🪜 三、五步教育的范例 <a class="header-anchor" href="#🪜-三、五步教育的范例" aria-label="Permalink to &quot;🪜 三、五步教育的范例&quot;">​</a></h2><div class="tc-container tc-container-blue" style="margin-top:20px;"><p class="tc-body" style="font-size:14px;line-height:1.8;"> 当我们遇到一个人时，如何让他清楚的知道我们想和他说话并拉近彼此的距离呢？（停顿一下，眼睛看着新同事，让他回答或引导他回答）→ <strong class="tc-blue">打招呼</strong>（很好→鼓励他）打招呼很简单的：嗨！您好！（让他跟你说一次，很好→鼓励他一下）当他熟悉了之后，提醒他为了拉近与客户彼此的距离让客户更容易接受我们→笑容，注意他手上File拿的位置和他的目光，（再和他练习，等他熟悉后再进入第二步） </p><p class="tc-body" style="font-size:14px;line-height:1.8;margin-top:12px;"> 打完招呼后客户会有两个问题：你是谁？你来做什么？所以我们<strong class="tc-blue">介绍自己</strong>就是要说明来意：我们是某某公司〈我们是谁〉今天在这里做活动〈来做什么〉（与他练习），注意他的眼神是否有信心、是否看着客户。 </p><p class="tc-body" style="font-size:14px;line-height:1.8;margin-top:12px;"> 说明了我们的来意后再来就要<strong class="tc-green">介绍产品</strong>了，首先要把产品放在客户的手上：特别送一张优惠券过来给您，来这个给您看一下，很多人都拿了，拿完了就没有了〈注意递DM到客户手中的位置〉（与他练习）。接下来简单的教他推广产品的特色、功能（与他练习），教他推广价格：这个一般商场要多少钱，我们今天做活动只要成本价才多少而已喔！因为数量有限所以我们用登记的方式，现在登记，下午送货，货送到、你点收、再付钱就可以了，现在登记不需要任何订金（与他练习）〈注意：要教他简单的控制场面〉 </p><p class="tc-body" style="font-size:14px;line-height:1.8;margin-top:12px;"> 接下来要引导跟试探客户的购买意愿，你看一下这个，前面很多人都登记了，喜欢的话麻烦您在这里写下您这里的地址和电话，方便我帮您送货过来，谢谢喔！ </p></div><div class="tc-grid tc-grid-auto" style="margin-top:15px;"><div class="tc-card tc-card-red"><p class="tc-subtitle tc-red">❌ 响应否定的客户</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 谢谢再见！ </p></div><div class="tc-card tc-card-orange"><p class="tc-subtitle tc-orange">🤔 没有响应（犹豫）的客户</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 帮他做决定：今天很多人都是两套四套在登记的，这样好了，您先登记一套试用看看吧！您贵姓（帮他写）！ </p></div><div class="tc-card tc-card-blue"><p class="tc-subtitle tc-blue">❓ 提问题的客户</p><p class="tc-body" style="font-size:14px;line-height:1.7;"> 解决他的问题并推广，再给他成交问题：今天很多人都是两套四套在登记的，这样好了，您先登记一套试用看看吧！您贵姓（帮他写）！ </p></div></div></div>',10)])])}const h=e(i,[["render",l]]);export{g as __pageData,h as default};
